import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import signupBg from '../assets/images/loginbg.png';

const Signup = () => {
  const [firstName, setFirstName] = useState('');
  const [middleName, setMiddleName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  
  const { signup, isAuthenticated } = useAuth();
  const navigate = useNavigate();

  // Redirect if already authenticated
  React.useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard');
    }
  }, [isAuthenticated, navigate]);

  const validateEmail = (email) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  };

  const validatePhone = (phone) => {
    const re = /^\+?[0-9\s\-]{7,15}$/;
    return re.test(phone);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    // Validation
    const fullName = `${firstName} ${middleName ? middleName + ' ' : ''}${lastName}`.trim();
    if (fullName.length < 3) {
      setError('Full name must be at least 3 characters');
      return;
    }

    if (!validateEmail(email.trim())) {
      setError('Please enter a valid email address');
      return;
    }

    if (!validatePhone(phone.trim())) {
      setError('Please enter a valid phone number');
      return;
    }

    if (username.trim().length < 3) {
      setError('Username must be at least 3 characters');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters');
      return;
    }

    setLoading(true);

    try {
      const result = await signup(fullName, email, password);
      
      if (result.success) {
        navigate('/dashboard');
      } else {
        setError(result.error || 'Signup failed. Please try again.');
      }
    } catch (err) {
      setError('An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const styles = {
    pageWrapper: {
      minHeight: '100vh',
      margin: 0,
      fontFamily: "'Cantata One', serif",
      backgroundRepeat: 'no-repeat',
      backgroundPosition: 'center center',
      backgroundSize: 'cover',
      backgroundAttachment: 'fixed',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '20px',
    },
    signupContainer: {
      background: 'white',
      padding: '30px 20px 40px 20px',
      width: '520px',
      boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
      borderRadius: '6px',
      textAlign: 'center',
    },
    form: {
      display: 'block',
    },
    logoContainer: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      marginBottom: '20px',
      gap: '10px',
    },
    logoIcon: {
      width: '36px',
      height: '36px',
      filter: 'drop-shadow(0 1px 0 rgba(0,0,0,0.1))',
    },
    logoTextMain: {
      fontWeight: '600',
      fontSize: '18px',
      color: '#000',
      userSelect: 'none',
    },
    logoTextSub: {
      fontSize: '11px',
      color: '#555',
      lineHeight: '1.1',
      userSelect: 'none',
    },
    heading: {
      margin: '0 0 6px 0',
      fontWeight: '600',
      fontSize: '20px',
      color: '#000',
      userSelect: 'none',
    },
    subtitle: {
      margin: '0 0 20px 0',
      fontSize: '13px',
      color: '#555',
      userSelect: 'none',
    },
    row: {
      display: 'flex',
      gap: '10px',
      marginBottom: '20px',
    },
    field: {
      flex: 1,
    },
    inputGroup: {
      position: 'relative',
      marginBottom: '0',
    },
    inputIcon: {
      position: 'absolute',
      top: '50%',
      left: '10px',
      transform: 'translateY(-50%)',
      color: '#888',
      fontSize: '17px',
      pointerEvents: 'none',
      userSelect: 'none',
    },
    input: {
      width: '100%',
      padding: '10px 12px',
      border: '1.5px solid #ccc',
      borderRadius: '5px',
      fontSize: '14px',
      transition: 'border-color 0.25s ease',
      outlineOffset: '2px',
      boxSizing: 'border-box',
    },
    usernameGroup: {
      position: 'relative',
      marginBottom: '15px',
    },
    signupBtn: {
      width: '100%',
      backgroundColor: '#3030cc',
      color: 'white',
      fontWeight: '600',
      padding: '12px 0',
      border: 'none',
      borderRadius: '8px',
      fontSize: '15px',
      cursor: 'pointer',
      transition: 'background-color 0.3s ease',
      userSelect: 'none',
      marginTop: '10px',
    },
    errorMessage: {
      color: '#e74c3c',
      fontSize: '11px',
      marginBottom: '12px',
      textAlign: 'left',
      userSelect: 'none',
      minHeight: '14px',
    },
  };

  return (
    <div style={{...styles.pageWrapper, backgroundImage: `url(${signupBg})`}}>
      <div style={styles.signupContainer}>
        <form id="signupForm" onSubmit={handleSubmit} noValidate style={styles.form}>
          {/* Logo */}
          <div style={styles.logoContainer}>
            <img
              src="https://img.icons8.com/ios-filled/50/0000FF/car.png"
              alt=""
              style={styles.logoIcon}
              aria-hidden="true"
              draggable="false"
            />
            <div>
              <div style={styles.logoTextMain}>Rent a Car</div>
              <div style={styles.logoTextSub}>Management System</div>
            </div>
          </div>

          <h2 style={styles.heading}>Create an account</h2>
          <p style={styles.subtitle}>Sign up to get started</p>

          {/* Error Message */}
          {error && (
            <div style={styles.errorMessage}>
              {error}
            </div>
          )}

          {/* Names Row */}
          <div style={styles.row}>
            <div style={styles.field}>
              <div style={styles.inputGroup}>
                <span style={styles.inputIcon} aria-hidden="true">👤</span>
                <input
                  type="text"
                  id="firstName"
                  name="firstName"
                  value={firstName}
                  onChange={(e) => setFirstName(e.target.value)}
                  placeholder="First Name"
                  autoComplete="given-name"
                  required
                  style={styles.input}
                  disabled={loading}
                />
              </div>
            </div>

            <div style={styles.field}>
              <div style={styles.inputGroup}>
                <span style={styles.inputIcon} aria-hidden="true">👤</span>
                <input
                  type="text"
                  id="middleName"
                  name="middleName"
                  value={middleName}
                  onChange={(e) => setMiddleName(e.target.value)}
                  placeholder="Middle Name"
                  autoComplete="additional-name"
                  required
                  style={styles.input}
                  disabled={loading}
                />
              </div>
            </div>

            <div style={styles.field}>
              <div style={styles.inputGroup}>
                <span style={styles.inputIcon} aria-hidden="true">👤</span>
                <input
                  type="text"
                  id="lastName"
                  name="lastName"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  placeholder="Last Name"
                  autoComplete="family-name"
                  required
                  style={styles.input}
                  disabled={loading}
                />
              </div>
            </div>
          </div>

          {/* Contact Row */}
          <div style={styles.row}>
            <div style={styles.field}>
              <div style={styles.inputGroup}>
                <span style={styles.inputIcon} aria-hidden="true">✉️</span>
                <input
                  type="email"
                  id="email"
                  name="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="Email"
                  autoComplete="email"
                  required
                  style={styles.input}
                  disabled={loading}
                />
              </div>
            </div>

            <div style={styles.field}>
              <div style={styles.inputGroup}>
                <span style={styles.inputIcon} aria-hidden="true">📞</span>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  placeholder="Phone"
                  autoComplete="tel"
                  required
                  pattern="^\+?[0-9\s\-]{7,15}$"
                  style={styles.input}
                  disabled={loading}
                />
              </div>
            </div>
          </div>

          {/* Username */}
          <div style={styles.usernameGroup}>
            <span style={styles.inputIcon} aria-hidden="true">👤</span>
            <input
              type="text"
              id="username"
              name="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Username"
              autoComplete="username"
              required
              minLength="3"
              style={styles.input}
              disabled={loading}
            />
          </div>

          {/* Password - plain no icons */}
          <div style={styles.usernameGroup}>
            <input
              type="password"
              id="password"
              name="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Password"
              autoComplete="new-password"
              required
              minLength="6"
              style={styles.input}
              disabled={loading}
            />
          </div>

          {/* Submit */}
          <button 
            type="submit" 
            style={styles.signupBtn}
            disabled={loading}
          >
            {loading ? 'Creating Account...' : 'Sign Up'}
          </button>
        </form>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cantata+One&display=swap');
        
        input:focus {
          border-color: #3030cc !important;
          outline: none;
        }
        
        button:hover:not(:disabled) {
          background-color: #1f1f8a !important;
        }
      `}</style>
    </div>
  );
};

export default Signup;
